INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Overview', 'non-harassment-overview', '<h2>Overview</h2>
<p>Individuals at Innovative Air Technologies have the right to work in an environment free from harassment and discrimination. This right is not only supported by company policies but also enshrined in various state and federal laws. Employees can be assured that any form of harassment or discrimination will not be tolerated and will be met with appropriate disciplinary actions.</p>
<p>As a company operating in Georgia, Innovative Air Technologies ensures that its non-harassment and non-discrimination policies are in full compliance with the state''s laws and regulations. By aligning with legal requirements, the company demonstrates its commitment to upholding the rights and well-being of its employees while fostering a culture of respect and equality.</p>', 1, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
