INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Sexual Harassment', 'sexual-harassment', '<h2>Sexual Harassment</h2>
<p><strong>Sexual harassment is defined as unwelcome sexual advances, requests for sexual favors and other verbal, visual or physical conduct of a sexual nature, when:</strong></p>
<ol>
  <li>Submission to such conduct is made either explicitly or implicitly a term or condition of an individual''s employment.</li>
  <li>Submission to or rejection of such conduct by an individual is used as the basis for employment decisions affecting such individual; or</li>
  <li>Such conduct has the purpose or effect of unreasonably interfering with an individual''s work performance or creating an intimidating, hostile or offensive working environment.</li>
</ol>
<p>Examples of sexual harassment include but are not limited to: unwelcome or unsolicited sexual advances; displaying sexually suggestive material; unwelcome sexual flirtations, advances or propositions; suggestive comments; verbal abuse of a sexual nature; sexually oriented jokes; crude or vulgar language or gestures; graphic or verbal commentaries about an individual''s body; display or distribution of obscene materials; physical contact such as patting, pinching or brushing against someone''s body; or physical assault of a sexual nature.</p>', 4, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'About Discriminatory Behavior', 'about-discriminatory-behavior', '<h2>About Discriminatory Behavior</h2>
<p>Discrimination is the act of <strong>treating a person or group differently, unjustly, or negatively based on their membership in a particular social category</strong>. This unequal treatment can take many forms, and can be intentional or unintentional.</p>
<p><strong>Below are a few examples of what we consider to be discriminatory behavior…</strong></p>
<h3>Examples of discrimination:</h3>
<ul>
  <li>Hiring managers disproportionately hiring / disqualifying candidates of a certain gender due to their own biases, knowingly.</li>
  <li>Managers that overlook employees with specific protected characteristics (such as race, religion) for raises / promotions and cannot prove they did so fairly.</li>
  <li>Someone making sexist / racist comments.</li>
  <li>Sending emails belittling an employee about any of their protected characteristics (such as race, religion, gender presentation, nationality, etc.).</li>
</ul>
<p>Obviously, this is not an exhaustive list. If you feel you have been harassed or discriminated against, please let your manager or HR rep know.</p>', 5, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What To Do if You See or Experience Discrimination', 'what-to-do-if-you-see-or-experience-discrimination', '<h2>What To Do if You See or Experience Discrimination</h2>
<p><strong>If you or someone you know is being discriminated against or harassed, tell your supervisor or HR right away!</strong></p>
<p>Any company employee who feels that he or she has been harassed or discriminated against or has witnessed or become aware of discrimination or harassment in violation of these policies, should bring the matter to the immediate attention of his or her supervisor, HR, or any other manager. We will promptly investigate all allegations of discrimination, harassment and act as appropriate based on the outcome of the investigation.</p>
<p>An investigation and its results will be treated as confidential to the extent feasible, and the company will take appropriate action based on the outcome of the investigation.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF captioned "Hello, I need to tattle" — re-upload via admin editor</figcaption></figure>
<p><strong>HR will spearhead an investigation of your claim, look into the situation, and then decide the best course of action for resolution for both the victim and the perpetrator.</strong></p>
<p><strong>NOTE:</strong> No employee will be retaliated against for making a complaint in good faith regarding a violation of these policies, or for participating in good faith in an investigation pursuant to these policies. If an employee feels he/she has been retaliated against, the employee should file a complaint using the procedures set forth above.</p>', 6, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Our Anti-discrimination Policy', 'our-anti-discrimination-policy', '<h2>Our Anti-discrimination Policy</h2>
<p>This is simple: <strong>We do not allow or tolerate, under any circumstance, ANY behavior, or actions that we or others may consider discriminatory or harassing.</strong></p>
<blockquote><p>Again, zero tolerance!</p></blockquote>
<p>Our anti-discrimination policy prohibits discrimination and harassment on the basis of an individual''s race, color, religion, national origin, sex, gender identity, sexual orientation, age, disability, or any other protected characteristic.</p>
<h3>Anti-discrimination policy:</h3>
<ol>
  <li><strong>Discrimination and harassment are prohibited</strong> in all aspects of employment, including hiring, promotion, compensation, benefits, training, discipline, and termination.</li>
  <li>Employees who <strong>experience</strong> harassment are <strong>encouraged</strong> to report the incident to their direct manager, or to HR. Employees who <strong>witness</strong> discrimination or harassment are <strong>required</strong> to report the incident to their direct manager or to HR.</li>
  <li>Reports of discrimination or harassment will be <strong>investigated promptly and thoroughly</strong>, and confidentiality will be maintained to the extent possible.</li>
  <li><strong>Retaliation</strong> against individuals who report discrimination or harassment or who participate in an investigation is <strong>strictly prohibited</strong>.</li>
  <li>Employees who <strong>engage</strong> in discrimination or harassment will be subject to disciplinary action, up to and including <strong>termination of employment</strong>.</li>
</ol>
<p><strong>We are committed to creating a workplace that is free from discrimination and harassment, and we will take all necessary steps to prevent and address incidents of discrimination and harassment.</strong></p>', 7, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'How We Prevent Discrimination and Harassment', 'how-we-prevent-discrimination-and-harassment', '<h2>How We Prevent Discrimination and Harassment</h2>
<p><strong>First and foremost, we encourage a culture of inclusion and mutual respect.</strong></p>
<p>To avoid potential harassment situations altogether, and to make sure we handle every case fairly and lawfully, we also do the following…</p>
<h3>Our steps towards prevention:</h3>
<ul>
  <li>We have a set series of rules that apply to job-related hiring, promoting, and rewarding employees to avoid accidental/purposeful discrimination.</li>
  <li>All compensation / benefits will be based on position, seniority, qualification, and performance — NOT based on protected characteristics.</li>
  <li>We make appropriate adjustments for all employees with disabilities.</li>
  <li>We ask that managers keep a log of their decisions regarding promotion / demotion, or anything really, of current employees or job candidates.</li>
</ul>', 8, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
