INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Drug &amp; Alcohol Policy', 'drug-and-alcohol-policy', '<h2>Drug &amp; Alcohol Policy</h2>
<p><strong>Employees are prohibited from unlawfully consuming, distributing, possessing, selling, or using controlled substances while on duty.</strong></p>
<p>In addition, employees may not be under the influence of any controlled substance, such as drugs or alcohol, while at work, on company premises or engaged in company business.</p>
<p><strong>Prescription drugs or over-the-counter medications, taken as prescribed, are an exception to this policy.</strong></p>
<p>Anyone violating this policy may be subject to disciplinary action, up to and including termination.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF of a person at a door (The Office) — re-upload via admin editor</figcaption></figure>
<p><strong>All newly hired employees are required to have a pre-hire drug screening.</strong></p>
<p>IAT reserves the right to randomly require drug screening at its discretion.</p>', 12, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
