INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Come on in!', 'come-on-in', '<h2>Come on in!</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF from Seinfeld showing someone at a door — re-upload via admin editor</figcaption></figure>
<p>At Innovative Air Technologies, we like to keep things chill and open. With our <strong><em>open door policy</em></strong>, no matter if you''re just starting out or if you''re on the leadership team, you can just pop in and chat with your supervisors anytime.</p>
<ul>
  <li>Got an idea?</li>
  <li>A bit of feedback?</li>
  <li>Something bugging you?</li>
  <li>Tell them about it.</li>
</ul>
<p><strong>We want to make sure everyone feels heard and valued.</strong></p>
<p>We get that every single person here is key to making IAT a world-class environment, and by keeping the lines of communication wide open, we can sort out any issues fast, keep everyone happy, and make our workplace not just productive but also a pretty great place to be.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: video embed titled "Open Door Policy Explained" — re-upload via admin editor</figcaption></figure>', 13, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Overview', 'payday-overview', '<h2>Overview</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: video embed titled "Getting Paid" — re-upload via admin editor</figcaption></figure>
<p><strong>Paychecks/Direct Deposits are distributed every Thursday. If the pay date lands on a holiday, paychecks will be distributed on the closest business day before the holiday.</strong></p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF captioned "SHOW" (Jerry Maguire money scene) — re-upload via admin editor</figcaption></figure>
<p>The paycheck will reflect work performed for the week prior to the pay date. Paychecks include salary or wages earned less any mandatory or elected deductions.</p>
<ol>
  <li>Mandatory deductions include federal or state withholding tax, and other withholdings.</li>
  <li>Elected deductions are deductions authorized by the employee, and may include, for example, contributions to benefit plans.</li>
</ol>
<p><a href="#">Employees may contact HR to obtain the necessary authorization forms to requesting additional deductions from their paychecks.</a></p>
<p>Notify a supervisor if the paycheck appears to be inaccurate. If there is an issue with direct deposit, or if it has been misplaced, IAT reserves the right to charge a replacement fee for any lost paychecks.</p>
<p>Advances on paychecks are not permitted. Information regarding final paychecks can be found under the termination section of this handbook.</p>
<p>Any change in bank account, name, address, telephone number, marital status or number of exemptions claimed by an employee must be reported to HR immediately.</p>', 14, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;

