INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Privacy at IAT', 'privacy-at-iat', '<h2>Privacy at IAT</h2>
<blockquote><p><em>At Innovative Air Technologies, we''re all about creating a work environment of trust and mutual respect.</em></p></blockquote>
<p>Keeping things running smoothly, protecting our assets, and making sure we''re all on the right side of the law are super important to us. That''s why we have guidelines in place about privacy and how we all should use the company''s gear.</p>
<p>We''ve tried to strike a balance with this policy. This helps IAT work like a well-oiled machine while also looking after our assets and standing by our values. We''re all in this together, so we encourage everyone to stay professional and make smart choices with the resources we''ve got.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Privacy Policy Introduction video thumbnail — re-upload via admin editor</figcaption></figure>', 8, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
