INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Company Property and Access', 'company-property-and-access', '<h2>Company Property and Access</h2>
<blockquote><p><strong>Company property refers to the physical assets owned by a business that are essential for its operations.</strong></p></blockquote>
<p>For Innovative Air Technologies, assets may include office buildings, manufacturing facilities, equipment, machinery, vehicles, computers, furniture, and other tangible assets used in the daily operations of the company. These assets are crucial for the business to function effectively and serve its customers.</p>
<p>In addition to tangible assets, <strong>company property also encompasses intellectual property</strong> such as patents, trademarks, copyrights, and trade secrets that are valuable assets for Innovative Air Technologies. These intellectual properties are protected by law and play a vital role in maintaining the company''s competitive edge in the market.</p>
<p>Access to company property is typically restricted to authorized personnel only to ensure security and prevent unauthorized use or theft. Employees may be granted access to specific company property based on their job responsibilities and level of authorization. It is important for employees to understand and adhere to the company''s policies and procedures regarding the use and protection of company property to maintain a safe and secure work environment.</p>', 9, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Expectation of Privacy', 'expectation-of-privacy', '<h2>Expectation of Privacy</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Could you give us some privacy for, like, one second?" meme — re-upload via admin editor</figcaption></figure>
<blockquote><p><strong>When it comes to company property and access, Innovative Air Technologies has established clear guidelines for employees to follow. The company retains the right to access, monitor, and inspect all company property at any time. This policy is in place to ensure compliance with security protocols and to protect the interests of the organization.</strong></p></blockquote>
<p>Employees should be aware that when using or storing personal items or information on company property, <strong>they should not expect privacy.</strong> This includes company-issued devices, email accounts, and storage areas. By using company property, employees are consenting to the monitoring and inspection of their activities to maintain a secure and productive work environment.</p>', 10, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Company Property?', 'what-is-company-property', '<h2>What is Company Property?</h2>
<blockquote><p><em>This policy is to ensure that company property is used appropriately for business purposes and returned in good condition when an employee leaves the company.</em></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: What is Company Property video thumbnail — re-upload via admin editor</figcaption></figure>
<p>Company property, such as equipment, vehicles, telephones, computers, and software, is not for private use. These devices are to be used strictly for company business and are not permitted off grounds unless authorized. Company property must be used in the manner for which it was intended. Upon termination, employees are required to surrender any company property they possess.</p>
<h3>Items to remember:</h3>
<ol>
<li><strong>Business Use Only:</strong> Company property, including equipment, computers, phones, and software, is to be used for business purposes only.</li>
<li><strong>Authorization for Private Use:</strong> If there is a need to use company property for private use, employees must seek approval from their manager.</li>
<li><strong>No Taking Home:</strong> Company property should not be taken home without proper authorization.</li>
<li><strong>Return Upon Departure:</strong> When an employee leaves the company, all company property must be returned as they are owned by the company.</li>
</ol>
<blockquote><p><strong>PLEASE NOTE:</strong></p>
<ul>
<li>Misuse of company property for private use without authorization is not allowed.</li>
<li>Taking company property home without permission can result in disciplinary action.</li>
<li>Failure to return company property upon departure may lead to legal consequences.</li>
</ul></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "I Have a Tip" meme — re-upload via admin editor</figcaption></figure>
<h3>Some tips for you...</h3>
<ul>
<li>Communicate with your manager if there is a need to use company property for private use.</li>
<li>Keep company property in good condition to ensure smooth operations.</li>
<li>Return all company property promptly when leaving the company to avoid any issues.</li>
</ul>', 11, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Company Computers', 'company-computers', '<h2>Company Computers</h2>
<blockquote><p><strong>Company computers, internet and emails are a privileged resource, and must be used only to complete essential job-related functions.</strong></p></blockquote>
<ol>
<li>Employees are not permitted to download any "pirated" software, files or programs and must receive permission from a supervisor before installing any new software on a company computer.</li>
<li>Files or programs stored on company computers may not be copied for personal use.</li>
<li>Phones are provided for business use.</li>
<li>The company requests that employees not receive personal calls while on-duty. If urgent, please keep personal calls to a minimum and conversations brief.</li>
<li>Employees are reminded that they should have no expectation of privacy in their use of company computers or other electronic equipment.</li>
<li>Violations of these policies could result in disciplinary action or termination.</li>
</ol>', 12, TRUE, 3
