INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Gossip Policy Overview', 'gossip-policy-overview', '<h2>Gossip Policy Overview</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Handling Gossip in the Workplace video thumbnail — re-upload via admin editor</figcaption></figure>
<p>At Innovative Air Technologies, fostering a positive and collaborative workplace culture is essential to our success. Gossip can undermine trust, disrupt teamwork, and create unnecessary tension among team members. This policy is designed to clarify what constitutes gossip and explain why maintaining a gossip-free environment is crucial for our shared goals.</p>
<blockquote><p><strong>Gossip = Discussing anything negative with someone who cannot resolve the problem.</strong></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Don''t Spill the Tea" meme — re-upload via admin editor</figcaption></figure>', 14, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Gossip?', 'what-is-gossip', '<h2>What is Gossip?</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "You need to stop spreading life-altering rumors about me" meme — re-upload via admin editor</figcaption></figure>
<blockquote><p><strong>Gossip is any informal communication that spreads unverified, private, or speculative information about others in the workplace.</strong></p></blockquote>
<p>It often includes:</p>
<ul>
<li>Sharing personal details about coworkers without their consent.</li>
<li>Discussing unconfirmed rumors about the company or its operations.</li>
<li>Talking negatively about someone who is not present to address the concerns.</li>
</ul>
<p>Even casual conversations can cross the line into gossip when they are inappropriate, unkind, or potentially harmful. Gossip is not the same as constructive feedback or problem-solving discussions aimed at improving work relationships or performance.</p>
<p><strong>In a nutshell, "gossip" is discussing anything negative about IAT, coworkers, or management with someone who can''t help solve the problem.</strong></p>', 15, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Why We Have a Gossip Policy', 'why-we-have-a-gossip-policy', '<h2>Why We Have a Gossip Policy</h2>
<p>Our commitment to integrity and teamwork means creating an environment where everyone feels respected, valued, and supported.</p>
<h3>A gossip-free workplace:</h3>
<ul>
<li>Builds trust and strengthens professional relationships.</li>
<li>Prevents misunderstandings, conflicts, and hurt feelings.</li>
<li>Encourages open, direct communication to resolve issues effectively.</li>
<li>Protects the reputation of employees and the company.</li>
</ul>
<blockquote><p><strong>By addressing gossip proactively, we aim to uphold a culture of professionalism and mutual respect, where everyone can thrive and focus on contributing their best to the team.</strong></p></blockquote>', 16, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Questions to Ask Before You Speak', 'gossip-questions-to-ask', '<h2>Questions to Ask Before You Speak</h2>
<blockquote><p><strong>Ask yourself before you speak:</strong></p></blockquote>
<h3>Is it True?</h3>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Is it true?" movie clip — re-upload via admin editor</figcaption></figure>
<p>Know the facts of any information you share. If you have not fact-checked that matter for yourself, avoid talking about it with other co-workers. You can always go to the individual and ask them for yourself. If you don''t feel comfortable doing so, either because of your comfort level with that person or because of the subject matter, you probably shouldn''t be discussing the matter at all.</p>
<h3>Is it Kind?</h3>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "The most important part about being famous is being kind" meme — re-upload via admin editor</figcaption></figure>
<p>If it seems like something outrageous or something that you wouldn''t want to get around about you, then don''t share, don''t judge, and don''t assume. Remember — if you can''t say anything nice, don''t say anything at all.</p>
<h3>Is it Necessary?</h3>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Is this really necessary?" meme — re-upload via admin editor</figcaption></figure>
<p>Another way to word this is — "Is it helpful for IAT?" In most circumstances, there is nothing productive about gossiping.</p>
<h3>Can this person make a difference?</h3>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Baseball field scene — re-upload via admin editor</figcaption></figure>
<p>If they can''t, discuss it with the person who can.</p>', 17, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Off-Limits Conversations', 'gossip-off-limits-conversations', '<h2>Off-Limits Conversations</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "You must not involve yourself" Shogun clip — re-upload via admin editor</figcaption></figure>
<h3>Conversations That Are Off Limits:</h3>
<ul>
<li><strong>Criminal behaviors</strong></li>
<li><strong>Alcoholism or drug addiction</strong></li>
<li><strong>Infidelity</strong></li>
<li><strong>Personal medical information</strong></li>
<li><strong>Sexuality</strong></li>
<li><strong>Anything that the general public would find reprehensible</strong></li>
</ul>', 18, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Ways to Respond to Gossip', 'gossip-ways-to-respond', '<h2>Ways to Respond to Gossip</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Hold My Beer" meme — re-upload via admin editor</figcaption></figure>
<h3>Ways to respond when approached with gossip:</h3>
<ul>
<li>Remove yourself from the conversation</li>
<li>Politely change the subject</li>
<li>Don''t repeat gossip you overhear</li>
<li>Directly state, "I''m not comfortable talking about __________."</li>
<li>Go directly to your supervisor or management to discuss the matter</li>
</ul>', 19, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Stop the Spread', 'gossip-stop-the-spread', '<h2>Stop the Spread</h2>
<blockquote><p><em>At Innovative Air Technologies, we all have a role in maintaining a respectful and collaborative workplace.</em></p></blockquote>
<p>By actively choosing to stop the spread of gossip, you help create an environment built on trust, integrity, and mutual respect. If you hear gossip, resist the urge to participate and instead redirect the conversation toward positive, productive topics.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Shut It Down" meme — re-upload via admin editor</figcaption></figure>', 20, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Gossip: Disciplinary Action', 'gossip-disciplinary-action', '<h2>Gossip: Disciplinary Action</h2>
<blockquote><p><strong><em>Engaging in gossip undermines our core values and will not be tolerated.</em></strong></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "I will not have it" reaction GIF — re-upload via admin editor</figcaption></figure>
<p>Employees who violate this policy may face disciplinary action, which could include verbal or written warnings, suspension, or, in severe cases, termination of employment. Our goal is to address such behavior constructively while protecting the well-being of the team.</p>
<blockquote><p><strong>Thank you for your commitment to fostering a supportive and professional workplace.</strong></p>
<p>Together, we can uphold our values and ensure that Innovative Air Technologies remains a place where everyone can thrive and succeed.</p></blockquote>', 21, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms Policy: Why We Have This Policy', 'weapons-firearms-why-we-have-this-policy', '<h2>Weapons and Firearms Policy: Why We Have This Policy</h2>
<blockquote><p><strong>At Innovative Air Technologies, maintaining a safe and secure workplace is a top priority.</strong></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Weapons and Firearms Policy Intro video thumbnail — re-upload via admin editor</figcaption></figure>
<p>A safe environment not only protects our employees, visitors, and contractors but also fosters a culture of trust and productivity.</p>
<p>The presence of weapons or firearms in the workplace can create unnecessary risks, cause fear or anxiety, and potentially escalate conflicts. To minimize these risks and ensure everyone feels secure, we have established this Weapons and Firearms Policy.</p>
<p>This policy is not intended to infringe on anyone''s rights but to balance those rights with our responsibility to provide a safe and professional environment. By adhering to these guidelines, we can collectively uphold the safety and well-being of everyone at IAT.</p>', 22, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms on Company Premises', 'weapons-firearms-on-company-premises', '<h2>Weapons and Firearms on Company Premises</h2>
<p>Weapons and firearms on company premises are strictly prohibited at Innovative Air Technologies (IAT). This policy applies to all individuals, including employees, visitors, contractors, and vendors, irrespective of possessing a valid permit to carry such items. The safety and security of everyone within IAT facilities are paramount, and the prohibition of weapons and firearms helps maintain a secure environment for all.</p>
<h3>Facilities include, but are not limited to:</h3>
<ul>
<li>Office spaces</li>
<li>Production Area</li>
<li>Storage areas</li>
<li>Parking lots (outside of vehicles)</li>
</ul>
<p>As part of IAT''s commitment to ensuring a safe workplace, the company enforces a <strong>zero-tolerance policy</strong> regarding weapons and firearms. This means that any individual found in possession of such items on company premises will face immediate disciplinary action, which may include termination of employment or removal from the premises.</p>
<p>By strictly enforcing this policy, IAT aims to create a secure and conducive work environment for all individuals associated with the company.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Employee photo — re-upload via admin editor</figcaption></figure>', 23, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms in Vehicles', 'weapons-firearms-in-vehicles', '<h2>Weapons and Firearms in Vehicles</h2>
<p>Employees are permitted to store weapons and firearms in their personal vehicles, as long as they are lawfully owned and in compliance with state and federal laws. These items must be stored securely, out of sight, and locked inside the vehicle at all times.</p>
<p>Employees who choose to keep weapons or firearms in their vehicles are responsible for maintaining the safety and security of these items. This includes ensuring that the weapons are properly secured and inaccessible to unauthorized individuals. By following these guidelines, employees can help maintain a safe and secure work environment for themselves and their colleagues.</p>', 24, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms: Exceptions', 'weapons-firearms-exceptions', '<h2>Weapons and Firearms: Exceptions</h2>
<blockquote><p><strong>This policy does not apply to authorized law enforcement officers or security personnel acting in their official capacity.</strong></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Law enforcement officers photo — re-upload via admin editor</figcaption></figure>', 25, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms: Violations and Reporting', 'weapons-firearms-violations-and-reporting', '<h2>Weapons and Firearms: Violations and Reporting</h2>
<blockquote><p><strong>Any violation of the company''s policy at Innovative Air Technologies (IAT) is taken very seriously and may result in disciplinary action.</strong></p></blockquote>
<p>Employees are expected to adhere to all policies and procedures in place to maintain a safe and productive work environment. Violations can range from minor interactions to more serious offenses, and the appropriate action will be taken based on the severity of the violation.</p>
<p>When it comes to visitors, contractors, or vendors found in violation of IAT''s policies, swift action will be taken. Any individual found to be in violation will be immediately removed from the premises. Additionally, they may be barred from future access to IAT facilities depending on the nature of the violation. This strict enforcement ensures that all individuals on company premises are held accountable for following the established policies and guidelines.</p>
<p>Employees who become aware of weapons or firearms inside IAT facilities or observe unsafe behavior related to weapons should immediately report the situation to their manager or HR.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Weapons and Firearms Violations and Reporting video thumbnail — re-upload via admin editor</figcaption></figure>', 26, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Attendance Policy Overview', 'attendance-policy-overview', '<h2>Attendance Policy Overview</h2>
<blockquote><p><em>Just come to work and you''ll be fine!</em></p></blockquote>
<p>Kidding! You get some time to yourself... but that''s in the Leave section, this section is all about showing up!</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Show" meme — re-upload via admin editor</figcaption></figure>', 27, TRUE, 2
