SELECT m.id, 'Breaks and Lunch', 'breaks-and-lunch', '<h2>Breaks and Lunch</h2>
<p>Employees are entitled to 10 minute breaks every two hours during the work day.</p>
<p>Lunch is for 1 hour each day.</p>
<h3>Break Times:</h3>
<ul>
<li>8:00 – 8:10</li>
<li>10:00 – 10:10</li>
<li>3:00 – 3:10</li>
</ul>
<h3>Lunch Time:</h3>
<ul>
<li>12:00 – 1:00</li>
</ul>
<blockquote><p><strong>Returning from Break or Lunch late will not be accepted. Be prompt.</strong></p></blockquote>', 30, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
