INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Common Types of Interpersonal Conflict', 'conflict-common-types', '<h2>Common Types of Interpersonal Conflict</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Two people arguing scene — re-upload via admin editor</figcaption></figure>
<ol>
<li><strong>Pseudo Conflict</strong> – Two people agree but think they don''t. Created by poor communication and assumptions.</li>
<li><strong>Fact Conflict</strong> – Two or more disagree about the facts of a topic or situation.</li>
<li><strong>Policy Conflict</strong> – A dispute over a course of action based on a policy or company guidelines.</li>
<li><strong>Value Conflict</strong> – An employee''s personal values do not align with company values. Or an individual''s values conflict with their coworkers.</li>
<li><strong>Ego Conflict</strong> – An individual takes everything personally.</li>
<li><strong>Meta Conflict</strong> – A disagreement about how a conflict is being handled or resolved. Essentially, a conflict about a conflict.</li>
</ol>', 49, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
