SELECT m.id, 'Conflict Mediation', 'conflict-mediation', '<h2>Conflict Mediation</h2>
<blockquote><p><em>If a conflict cannot be resolved between two individuals, management-lead mediation may be necessary.</em></p></blockquote>
<h3>This mediation may include, but is not limited to:</h3>
<ol>
<li><strong>Individual Meetings:</strong> Separate meetings with each party to understand perspectives with open and honest discussions.</li>
<li><strong>Joint Exploration:</strong> Joint meetings with all involved parties with established boundaries.</li>
<li><strong>Negotiation:</strong> Collaborative problem-solving by identifying common ground and working towards a win-win solution.</li>
</ol>
<figure class="img-missing"><figcaption>📷 Image from Trainual: How Does Workplace Mediation Work? YouTube video — re-upload via admin editor</figcaption></figure>', 52, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
